#!/usr/bin/env python3
import os, zlib, hashlib, json
from pathlib import Path

GIT_DIR = Path('/home/ctfplayer/ctf_files/sourcery_unz/.git')
OBJ_DIR = GIT_DIR/'objects'
OUT = Path('/home/ctfplayer/ctf_files/sourcery_unz/recovered')
OUT.mkdir(exist_ok=True)

objects = {}

def read_loose_objects():
    for d in OBJ_DIR.iterdir():
        if len(d.name)!=2 or not d.is_dir() or d.name in ('info','pack'): continue
        for f in d.iterdir():
            sha = d.name + f.name
            raw = f.read_bytes()
            dec = zlib.decompress(raw)
            nul = dec.index(b'\x00')
            hdr = dec[:nul].decode()
            typ, size = hdr.split(' ')
            size = int(size)
            data = dec[nul+1:]
            objects[sha] = {'type':typ,'size':size,'data':data}


def parse_tree(data):
    i=0
    entries=[]
    while i < len(data):
        j = data.find(b' ', i)
        mode = data[i:j].decode()
        i = j+1
        j = data.find(b'\x00', i)
        name = data[i:j].decode('utf-8', errors='replace')
        i = j+1
        sha_raw = data[i:i+20]
        i += 20
        sha = sha_raw.hex()
        entries.append((mode,name,sha))
    return entries


def walk_tree(tree_sha, prefix=''):
    out=[]
    t = objects[tree_sha]
    for mode,name,sha in parse_tree(t['data']):
        p = f"{prefix}{name}"
        typ = objects.get(sha,{}).get('type','missing')
        out.append((p,mode,sha,typ))
        if typ=='tree':
            out.extend(walk_tree(sha,p+'/'))
    return out


def parse_commit(data):
    text = data.decode('utf-8', errors='replace')
    lines = text.splitlines()
    info={'parents':[]}
    msg=[]
    in_msg=False
    for ln in lines:
        if in_msg:
            msg.append(ln)
            continue
        if ln=='':
            in_msg=True
            continue
        if ln.startswith('tree '): info['tree']=ln.split()[1]
        elif ln.startswith('parent '): info['parents'].append(ln.split()[1])
        elif ln.startswith('author '): info['author']=ln[7:]
        elif ln.startswith('committer '): info['committer']=ln[10:]
    info['message']='\n'.join(msg).strip()
    return info


def main():
    read_loose_objects()
    summary = {}
    for sha,obj in objects.items():
        preview = obj['data'][:120]
        try:
            pstr = preview.decode('utf-8')
        except:
            pstr = repr(preview)
        summary[sha]={'type':obj['type'],'size':obj['size'],'preview':pstr}

    (OUT/'object_summary.json').write_text(json.dumps(summary,indent=2))

    commits={}
    for sha,obj in objects.items():
        if obj['type']=='commit':
            commits[sha]=parse_commit(obj['data'])

    (OUT/'commits.json').write_text(json.dumps(commits,indent=2))

    # roots/heads from refs and logs
    heads=[]
    refs_dir = GIT_DIR/'refs'/'heads'
    if refs_dir.exists():
        for rf in refs_dir.rglob('*'):
            if rf.is_file():
                heads.append((str(rf.relative_to(GIT_DIR)), rf.read_text().strip()))

    # include HEAD
    head = (GIT_DIR/'HEAD').read_text().strip()

    lines=[]
    lines.append(f"HEAD: {head}")
    lines.append('Branches:')
    for n,s in heads: lines.append(f"  {n} -> {s}")
    lines.append('Commits:')
    for c,info in commits.items():
        lines.append(f"{c} parents={info.get('parents',[])} tree={info.get('tree')} msg={info.get('message')}")
    (OUT/'commit_graph.txt').write_text('\n'.join(lines))

    # recover per commit files
    percommit = {}
    for c,info in commits.items():
        tree = info['tree']
        files = walk_tree(tree)
        percommit[c]=files
        cdir = OUT/'commits'/c
        cdir.mkdir(parents=True, exist_ok=True)
        flines=[]
        for p,mode,sha,typ in files:
            flines.append(f"{mode} {typ} {sha} {p}")
            if typ=='blob':
                data = objects[sha]['data']
                outp = cdir/p
                outp.parent.mkdir(parents=True, exist_ok=True)
                outp.write_bytes(data)
        (cdir/'_filelist.txt').write_text('\n'.join(flines))

    (OUT/'percommit_filelists.json').write_text(json.dumps({k:[{'path':p,'mode':m,'sha':s,'type':t} for p,m,s,t in v] for k,v in percommit.items()},indent=2))

    # dump suspicious blobs
    sus = ['5599f571ae392f04601e49ceceb50fe00f7a6184','924a7313c79582fa75acb6584eb14f6d10443091']
    sdir = OUT/'suspicious'
    sdir.mkdir(exist_ok=True)
    for s in sus:
        if s in objects:
            (sdir/f'{s}.bin').write_bytes(objects[s]['data'])

if __name__=='__main__':
    main()

