import marshal,types,dis,binascii,struct,sys

def parse_pyc(path):
    with open(path,'rb') as f: data=f.read()
    print(f'== {path} ==')
    print('size',len(data))
    print('magic',binascii.hexlify(data[:4]).decode())
    flags=struct.unpack('<I',data[4:8])[0]
    print('flags',hex(flags))
    print('header16',binascii.hexlify(data[:16]).decode())
    co=marshal.loads(data[16:])
    return co

def walk_code(co,indent=0):
    pad='  '*indent
    print(f"{pad}code name={co.co_name} argcount={co.co_argcount} locals={co.co_varnames}")
    print(f"{pad}consts:")
    for i,c in enumerate(co.co_consts):
        if isinstance(c,types.CodeType):
            print(f"{pad}  [{i}] <code {c.co_name}>")
        else:
            print(f"{pad}  [{i}] {c!r}")
    print(f"{pad}dis:")
    dis.dis(co)
    print()
    for c in co.co_consts:
        if isinstance(c,types.CodeType):
            walk_code(c,indent+1)

if __name__=='__main__':
    for p in sys.argv[1:]:
        co=parse_pyc(p)
        walk_code(co)
